// 核心定时器逻辑：从队列读取流式 Token，累积到 LVGL 气泡标签中
// [DONE] 到达时，直接从气泡标签取完整回复文本，存入全局链表
static void llm_check_timer_cb(lv_timer_t * timer) {
    if (llm_reply_queue == NULL) return;

    char *ai_reply_text = NULL;
    
    while (xQueueReceive(llm_reply_queue, &ai_reply_text, 0) == pdPASS) {
        if (ai_reply_text != NULL) {
            
            if (strcmp(ai_reply_text, "[DONE]") == 0) {
                ESP_LOGI(TAG2, "UI: stream transfer fully completed");

                // 直接从 LVGL 气泡标签取完整回复文本（无需额外缓冲）
                const char *full_reply = "";
                if (current_ai_label != NULL) {
                    full_reply = lv_label_get_text(current_ai_label);
                }
                
                if (g_pending_question != NULL && full_reply != NULL && full_reply[0] != '\0') {
                    ESP_LOGI(TAG2, "Save Q&A pair to global list: Q='%s' A='%s'", g_pending_question, full_reply);
                    ai_msg_add(g_pending_question, full_reply);
                } else {
                    ESP_LOGW(TAG2, "Skip save: pending=%p reply=%s", g_pending_question, full_reply);
                }
                
                // 清理临时缓冲
                if (g_pending_question != NULL) {
                    free(g_pending_question);
                    g_pending_question = NULL;
                }
                current_ai_label = NULL;
                
                free(ai_reply_text);
                
                if (ui_llm_timer != NULL) {
                    lv_timer_pause(ui_llm_timer);
                    ESP_LOGI(TAG2, "Timer paused, release CPU");
                }
                ai_busy = false;
                continue; 
            }

            if (current_ai_label == NULL) {
                ESP_LOGI(TAG2, "First streaming token, create new AI bubble: %s", ai_reply_text);
                add_chat_bubble(ai_reply_text, false); 
            } else {
                lv_label_ins_text(current_ai_label, LV_LABEL_POS_LAST, ai_reply_text);
                
                lv_obj_t *bubble = lv_obj_get_parent(current_ai_label);
                lv_obj_scroll_to_view_recursive(bubble, LV_ANIM_OFF);
            }

            free(ai_reply_text); 
        }
    }
}

// 添加聊天气泡
void add_chat_bubble(const char *text, bool is_user) {
    // 创建气泡容器
    lv_obj_t *bubble = lv_obj_create(ui_ChatContainer);
    lv_obj_set_width(bubble, 250); 
    lv_obj_set_height(bubble, LV_SIZE_CONTENT); 
    
    if(is_user) {
        lv_obj_set_align(bubble, LV_ALIGN_TOP_RIGHT); 
        lv_obj_set_style_bg_color(bubble, lv_palette_main(LV_PALETTE_BLUE), 0);
    } else {
        lv_obj_set_align(bubble, LV_ALIGN_TOP_LEFT);
        lv_obj_set_style_bg_color(bubble, lv_palette_main(LV_PALETTE_GREY), 0);
    }

    lv_obj_set_style_radius(bubble, 10, 0);
    lv_obj_set_style_border_width(bubble, 0, 0);
    lv_obj_set_style_pad_all(bubble, 8, 0); 

    // 创建文字 Label
    lv_obj_t *label = lv_label_create(bubble);
    lv_label_set_long_mode(label, LV_LABEL_LONG_WRAP); 
    lv_label_set_text(label, text);
    lv_obj_set_width(label, lv_pct(100)); 
    lv_obj_set_style_text_color(label, lv_color_white(), 0);
    lv_obj_set_style_text_align(label, LV_TEXT_ALIGN_LEFT, 0); 
    
    // 如果是 AI 产生的气泡，绑定到全局静态变量，供定时器后续追加
    if (!is_user) {
        current_ai_label = label;
    }

    // 自动滚动到最新消息
    lv_obj_scroll_to_view_recursive(bubble, LV_ANIM_ON);
}

