// ── 复用：构建诊断数据（电压/电流/抖动/噪声/诊断/置信度） ──
static int build_diagnosis_data(char *buf, int buf_size)
{
    int off = 0;
    bool first;
    uint16_t i;
    uint16_t pt_count = CHART2_DATA_POINTS;

    off += snprintf(buf + off, buf_size - off, "voltage=[");
    first = true;
    for (i = 0; i < pt_count && off < buf_size - 8; i++) {
        off += snprintf(buf + off, buf_size - off,
                        "%s%.2f", first ? "" : ",", ui_Chart2_series_2_array[i] / 100.0);
        first = false;
    }
    off += snprintf(buf + off, buf_size - off, "]");

    off += snprintf(buf + off, buf_size - off, ", current=[");
    first = true;
    for (i = 0; i < pt_count && off < buf_size - 8; i++) {
        off += snprintf(buf + off, buf_size - off,
                        "%s%.2f", first ? "" : ",", ui_Chart2_series_1_array[i] / 100.0);
        first = false;
    }
    off += snprintf(buf + off, buf_size - off, "]");

    off += snprintf(buf + off, buf_size - off, ", jitter=[");
    first = true;
    for (i = 0; i < HISTORY_WINDOW; i++) {
        if (jitter_level_history[i][0] != '\0') {
            off += snprintf(buf + off, buf_size - off,
                            "%s%s", first ? "" : ",", jitter_level_history[i]);
            first = false;
        }
    }
    off += snprintf(buf + off, buf_size - off, "]");

    off += snprintf(buf + off, buf_size - off, ", noise=[");
    first = true;
    for (i = 0; i < HISTORY_WINDOW; i++) {
        if (sound_level_history[i][0] != '\0') {
            off += snprintf(buf + off, buf_size - off,
                            "%s%s", first ? "" : ",", sound_level_history[i]);
            first = false;
        }
    }
    off += snprintf(buf + off, buf_size - off, "]");

    off += snprintf(buf + off, buf_size - off,
                    ", diagnosis=%s, confidence=%s",
                    Screen3_dqtd_text, Screen3_zxd_text);
    return off;
}

// ── 复用：展示气泡 + 发送 AI 请求 ──
static void send_ai_prompt(const char *prompt, const char *display_text)
{
    if (ai_busy) {
        ESP_LOGW(TAG2, "AI request in progress, ignoring rapid click");
        return;
    }
    ai_busy = true;

    add_chat_bubble(display_text, true);

    current_ai_label = NULL;
    if (g_pending_question != NULL) free(g_pending_question);
    g_pending_question = (char *)malloc(strlen(display_text) + 1);
    if (g_pending_question != NULL) {
        strcpy(g_pending_question, display_text);
    }

    lv_refr_now(NULL);

    if (ui_llm_timer != NULL) {
        lv_timer_resume(ui_llm_timer);
    }

    esp_err_t err = llm_cloud_request_stream(prompt);
    if (err != ESP_OK) {
        add_chat_bubble("request error: please try again later", false);
        if (ui_llm_timer != NULL) {
            lv_timer_pause(ui_llm_timer);
        }
        current_ai_label = NULL;  // 失败时复位，避免下次追加到错误气泡
        ai_busy = false;
    }
}

