{
    if (lv_event_get_code(e) == LV_EVENT_CLICKED) {
        char prompt[2048];
        int off = snprintf(prompt, sizeof(prompt), "Based on ");
        off += build_diagnosis_data(prompt + off, sizeof(prompt) - off);
        snprintf(prompt + off, sizeof(prompt) - off,
                 " verify the MCU diagnosis accuracy and share your analysis.");
        send_ai_prompt(prompt, "Please conduct an analysis");
    }
}

