// 发送按钮
void ui_event_fsBtnc(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);

    if(event_code == LV_EVENT_CLICKED) {
        if (ai_busy) {
            ESP_LOGW(TAG2, "AI request in progress, ignoring rapid send");
            return;
        }
        const char *txt = lv_textarea_get_text(ui_AiInp);
        
        if(strlen(txt) > 0) {
            ai_busy = true;
            ESP_LOGI(TAG2, "Add user bubble: %s", txt);
            add_chat_bubble(txt, true);

            // 每次发送新问题时，强制复位 AI 气泡指针，确保新回复创建新气泡
            current_ai_label = NULL;

            // 保存当前问题到临时缓冲（等待 AI 回复完成后一并存入全局链表）
            if (g_pending_question != NULL) free(g_pending_question);
            g_pending_question = (char *)malloc(strlen(txt) + 1);
            if (g_pending_question != NULL) {
                strcpy(g_pending_question, txt);
            } else {
                ESP_LOGE(TAG2, "Failed to alloc pending question!");
            }
            
            lv_refr_now(NULL); 
            ESP_LOGI(TAG2, "screen refresh done");

            // 启动定时器，准备接收流式响应
            if (ui_llm_timer != NULL) {
                lv_timer_resume(ui_llm_timer);
                ESP_LOGI(TAG2, "Timer started, ready to receive AI response");
            }

            // 调用你的网络
            esp_err_t err = llm_cloud_request_stream(txt);
            
            ESP_LOGI(TAG2, "network layer done");
            if(err != ESP_OK) {
                add_chat_bubble("request error: please try again later", false);
                if (ui_llm_timer != NULL) {
                    lv_timer_pause(ui_llm_timer);
                }
                ai_busy = false;
            } else {
                lv_textarea_set_text(ui_AiInp, "");
            }
        }
    }
}

