    if (ui_llm_timer == NULL) {
        ui_llm_timer = lv_timer_create(llm_check_timer_cb, 100, NULL);
        lv_timer_pause(ui_llm_timer); // 初始暂停，发送消息时再启动
        ESP_LOGI(TAG2, "成功创建大模型检测定时器（初始暂停状态）");
    }

    // 从全局链表恢复历史对话气泡（页面跳转后不丢失）
    {
        ai_msg_node_t *cur = ai_msg_get_head();
        uint8_t restored = 0;
        while (cur != NULL) {
            if (cur->question != NULL) {
                add_chat_bubble(cur->question, true);
            }
            if (cur->answer != NULL) {
                add_chat_bubble(cur->answer, false);
            }
            cur = cur->next;
            restored++;
        }
        ESP_LOGI(TAG2, "Restored %d Q&A pairs from global list", restored);
        current_ai_label = NULL;  // 重建后复位，避免新回复追加到旧气泡
    }

